/* Drifting paper grain — diagonal lines that slowly scroll diagonally.
   Opacity 0.07 = subtle but actually visible on cream bg. */
@keyframes grainDrift {
  0%   { background-position: 0 0; }
  100% { background-position: 40px 40px; }
}
