@import url('https://fonts.googleapis.com/css2?family=Quicksand:wght@400;500;600;700&family=Fira+Code:wght@400;500&display=swap');
*, *::before, *::after { font-family: 'Quicksand', system-ui, sans-serif !important; font-weight: 500; letter-spacing: 0.02em; }
code, pre, kbd, [class*="codeBlock"], [class*="markup"] code { font-family: 'Fira Code', monospace !important; }

/* Petals — one shared keyframe, 5 elements with different left% + speed + negative delay.
   Negative delays start each petal already mid-flight on load = no sync bursts.
   Spread across the full width so a petal can appear almost anywhere. */
@keyframes petalRise {
  0%   { transform: translateY(0)      translateX(0px)   rotate(0deg);   opacity: 0;    }
  5%   { opacity: 0.55; }
  30%  { transform: translateY(-30vh)  translateX(14px)  rotate(80deg);  opacity: 0.45; }
  60%  { transform: translateY(-62vh)  translateX(-10px) rotate(200deg); opacity: 0.30; }
  90%  { transform: translateY(-92vh)  translateX(8px)   rotate(320deg); opacity: 0.10; }
  100% { transform: translateY(-108vh) translateX(0px)   rotate(360deg); opacity: 0;    }
}
body::before {
  content: "🌸"; position: fixed; bottom: -50px; left: 8%;
  font-size: 14px; pointer-events: none; z-index: 999999;
  filter: drop-shadow(0 0 5px rgba(232,112,144,0.5));
  animation: petalRise 12s ease-in-out -2s infinite;
}
body::after {
  content: "🌸"; position: fixed; bottom: -50px; left: 31%;
  font-size: 10px; pointer-events: none; z-index: 999999;
  filter: drop-shadow(0 0 4px rgba(192,138,224,0.45));
  animation: petalRise 15s ease-in-out -8s infinite;
}
html::before {
  content: "🌸"; position: fixed; bottom: -50px; left: 57%;
  font-size: 16px; pointer-events: none; z-index: 999999;
  filter: drop-shadow(0 0 5px rgba(232,112,144,0.4));
  animation: petalRise 10s ease-in-out -5s infinite;
}
html::after {
  content: "🌸"; position: fixed; bottom: -50px; left: 74%;
  font-size: 12px; pointer-events: none; z-index: 999999;
  filter: drop-shadow(0 0 4px rgba(192,138,224,0.4));
  animation: petalRise 18s ease-in-out -13s infinite;
}
:root::before {
  content: "🌸"; position: fixed; bottom: -50px; left: 91%;
  font-size: 9px; pointer-events: none; z-index: 999999;
  filter: drop-shadow(0 0 3px rgba(232,112,144,0.35));
  animation: petalRise 13s ease-in-out -1s infinite;
}

