@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600&family=JetBrains+Mono:wght@400;500&display=swap');
*, *::before, *::after { font-family: 'Inter', system-ui, -apple-system, sans-serif !important; font-feature-settings: 'cv02', 'cv03', 'cv04', 'cv11' !important; letter-spacing: -0.005em; }
code, pre, kbd, [class*="codeBlock"], [class*="markup"] code { font-family: 'JetBrains Mono', 'Fira Code', monospace !important; }

/* Storm clouds — wide dark shapes drifting left→right across the top of screen.
   translateX animation on fixed elements (same axis as Abyss sonar = confirmed working).
   Two clouds at different heights, speeds, delays = staggered natural feel. */
@keyframes cloudDrift1 {
  0%   { transform: translateX(-160vw); }
  100% { transform: translateX(110vw);  }
}
@keyframes cloudDrift2 {
  0%   { transform: translateX(-160vw); }
  100% { transform: translateX(110vw);  }
}
body::before {
  content: "";
  position: fixed; top: -30px; left: 0;
  width: 55vw; height: 90px;
  background: radial-gradient(ellipse 50% 50% at 50% 50%,
    rgba(10,18,34,0.55) 0%,
    rgba(10,18,34,0.30) 50%,
    transparent 100%
  );
  pointer-events: none; z-index: 999999;
  animation: cloudDrift1 45s linear infinite;
}
body::after {
  content: "";
  position: fixed; top: 10px; left: 0;
  width: 70vw; height: 70px;
  background: radial-gradient(ellipse 50% 50% at 50% 50%,
    rgba(8,14,28,0.45) 0%,
    rgba(8,14,28,0.20) 55%,
    transparent 100%
  );
  pointer-events: none; z-index: 999998;
  animation: cloudDrift2 62s linear 18s infinite;
}
